export default function(file) {

  return new Promise((resolve, reject) => {

    const reader = new FileReader();
    const HEADER_SIZE = 8192;
    const headerSlice = file.slice(0, HEADER_SIZE);
    const imgSlice = file.slice(HEADER_SIZE, file.size);
    const imageDataSize = imgSlice.size;

    let W, H;
    let guessedBitDepth = 0;

    const dim = view => [view.getUint32(772, false), view.getUint32(776, false)];

    reader.onerror = (err) => reject(new Error(`FileReader error: ${err}`));

    reader.onloadend = e => {

      if (e.target.readyState !== FileReader.DONE) return;

      const buffer = e.target.result; // ArrayBuffer

      // --- Step 1: Process Header Slice ---
      if (buffer.byteLength === HEADER_SIZE) {

        try {

          const headerView = new DataView(buffer);

          [W, H] = dim(headerView);

          if (!W || !H || W <= 0 || H <= 0) {
            return reject(new Error(`Invalid dimensions: ${W}x${H}`));
          }

          const expectedSize8bit = W * H * 4;
          const expectedSize10bit = W * H * 4;
          const expectedSize16bit = W * H * 6;

          const diff8 = Math.abs(imageDataSize - expectedSize8bit);
          const diff10 = Math.abs(imageDataSize - expectedSize10bit);
          const diff16 = Math.abs(imageDataSize - expectedSize16bit);
          const minDiff = Math.min(diff8, diff10, diff16);

          if (minDiff === diff10) guessedBitDepth = 10;
          else if (minDiff === diff8) guessedBitDepth = 8;
          else if (minDiff === diff16) guessedBitDepth = 16;
          else guessedBitDepth = 8;

          reader.readAsArrayBuffer(imgSlice);

        } catch (headerError) {
          reject(new Error(`Error processing header: ${headerError.message}`));
        }

      } else {

        try {

          const imageView = new DataView(buffer);
          const outData = new Uint8Array(W * H * 4);
          let bytesRead = 0;
          let error = null;

          if (guessedBitDepth === 10) {

            for (let p = 0; p < W * H; p++) {
              if (bytesRead + 3 >= imageView.byteLength) { error = "10bit overrun"; break; }
              const word = imageView.getUint32(bytesRead, false); // Big Endian
              const i = p * 4;
              outData[i    ] = ((word >> 22) & 0x3FF) >> 2; // R10 -> R8
              outData[i + 1] = ((word >> 12) & 0x3FF) >> 2; // G10 -> G8
              outData[i + 2] = ((word >>  2) & 0x3FF) >> 2; // B10 -> B8
              outData[i + 3] = 255;
              bytesRead += 4;
            }

          } else if (guessedBitDepth === 16) {

            for (let p = 0; p < W * H; p++) {
              if (bytesRead + 5 >= imageView.byteLength) { error = "16bit overrun"; break; }
              const i = p * 4;
              outData[i    ] = imageView.getUint16(bytesRead    , false) >> 8; // R16 -> R8
              outData[i + 1] = imageView.getUint16(bytesRead + 2, false) >> 8; // G16 -> G8
              outData[i + 2] = imageView.getUint16(bytesRead + 4, false) >> 8; // B16 -> B8
              outData[i + 3] = 255;
              bytesRead += 6;
            }

          } else {

            for (let p = 0; p < W * H; p++) {
              if (bytesRead + 3 >= imageView.byteLength) { error = "8bit overrun"; break; }
              const i = p * 4;
              // Read 4 bytes, combine BE (matching r32 implicit BE)
              const pixel = imageView.getUint32(bytesRead, false);
              outData[i    ] = (pixel >> 24) & 255;
              outData[i + 1] = (pixel >> 14) & 255;
              outData[i + 2] = (pixel >>  4) & 255;
              outData[i + 3] = 255;
              bytesRead += 4;
            }

          }

          if (error) {
            console.error(`Pixel reading failed: ${error}`);
            return reject(new Error(`Error processing image data: ${error}`));
          }

          resolve({ width: W, height: H, data: outData });

        } catch (imageError) {

          reject(new Error(`Error processing image data: ${imageError.message} ${imageError.stack}`));

        }

      }

    };

    reader.readAsArrayBuffer(headerSlice);

  });

}